INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-b20a8cf8-moex-00114', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '司法警察官、司法警察拘提或逮捕現行犯，得經檢察官之許可，不予解送，下列何種案件不適用之？', '["中華民國刑法第310條第2項散布文字、圖畫毀損他人名譽之誹謗罪", "中華民國刑法第266條第2項以電信設備、電子通訊、網際網路或其他相類之方法賭博財物", "中華民國刑法第150條第1項公然聚眾施強暴脅迫罪之下手實施者", "中華民國刑法第161條第1項脫逃罪"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00115', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '下列有關警詢及筆錄製作之敘述，何者錯誤？', '["詢問被告或犯罪嫌疑人之錄音及錄影，應自開始詢問其姓名、年齡、職業及住所或居所時起錄， 至詢問完畢時停止，其間始末連續為之", "無辯護人之犯罪嫌疑人表示已選任辯護人時，在辯護人到場前，仍得繼續訊問", "犯罪嫌疑人於夜間經拘提或逮捕到場，為查驗其人有無錯誤者，司法警察官或司法警察得於夜 間詢問之", "詢問犯罪嫌疑人時，應給予辯明犯罪嫌疑之機會；如有辯明，應命其就始末連續陳述；其陳述 有利之事實者，應命其指出證明之方法，並於筆錄內記載明確"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00116', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '家暴慣犯甲男與髮妻乙女離異後，對乙女舊情未了，企圖復婚經常撥打乙女電話，且不定時前往 乙女工作地點徘迴，等待乙女下班。乙女不堪其擾，就近前往現居地之保三總隊第二大隊隊部報 案。關於乙女之報案，下列敘述何者有誤？', '["甲、乙固曾有婚姻關係，但甲之跟蹤騷擾行為明顯違法，仍應適用跟蹤騷擾防制法關於保護令 之規定", "甲經警察機關書面告誡後2年內，再為跟蹤騷擾行為者，被害人得向法院聲請保護令", "保三警察總隊受理跟蹤騷擾案件後，應移請管轄警察機關接續辦理", "司法警察官為調查甲男犯罪情形、蒐集證據，認有調取通信紀錄及通訊使用者資料之必要時， 不受通訊保障及監察法第11條之1第1項最重本刑3年以上有期徒刑之罪之限制"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00117', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '下列關於「各級警察機關處理刑案逐級報告紀律規定」及「警察偵查犯罪手冊」有關受理報案規 定之敘述，何者正確？', '["普通刑案之發生與破獲雖無須通報偵防中心，但經發現未填報刑案紀錄表，不論是否於時限內 補行填報刑案紀錄表，均視為匿報", "各級單位或員警個人接獲報案，如非屬其管轄責任之案件，應即迅速通知管轄分局勤務指揮中 心處理，以免貽誤偵辦時機", "受理告訴乃論案件，除應詢問告訴人是否提出告訴，並記明筆錄，若屬相對告訴乃論之罪，並 應告知告訴人應指明犯罪行為人", "警察機關受理事涉兩岸地區之刑事案件，以被害人或報案人戶籍所在地為管轄單位，不得以發 生地或涉案人在大陸地區而拒絕受理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00118', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '按刑事訴訟法及刑事訴訟特殊強制處分執行辦法規定，有關司法警察官、司法警察為調查犯罪情 形或蒐集證據認有必要時，得運用科技偵查設備以進行犯罪調查之敘述，下列何者錯誤？', '["司法警察機關得運用全球衛星定位系統查緝未稅菸品走私", "司法警察機關得利用設備端通訊監察偵辦加密貨幣洗錢", "司法警察機關得使用熱顯像儀於豪宅外偵測室內種植大麻", "司法警察機關依刑事訴訟法第153條之6第1項規定逕行實施特殊強制處分者，如經檢察官核 復不許可，或自報請檢察官許可之日起逾3日未獲檢察官許可時，執行機關應立即停止實施"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "e30848c8ec44", "answer_pdf_sha1": "f657f03fa6c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "1204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00119', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'essay', '英文作文：（25分）
近年來，詐騙（scam）集團日益猖獗，針對此現象，請寫一篇長約 200
字的英文短文，首先在第一段中，說明詐騙常見的型態，其次在第二
段中，教導民眾如何預防詐騙。', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "0205", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00120', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '立法委員於審議經濟部之年度預算時，提議將某預算科目的一定比例移至其他科目，但預算 總額並未增加。依憲法及司法院大法官解釋，下列敘述何者正確？', '["立法委員本來即有審議預算的權力，故其提議並未牴觸憲法", "立法委員之預算變動有實質正當理由，其變動即屬合憲", "預算總額於移動後並無增加，即無增加政府支出，故非憲法所不許", "預算總額雖未增加，但就被移動而增加或追加之原預算項目而言，亦屬增加支出之提議， 而與憲法不符"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00121', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依司法院大法官解釋，有關人民義務之規定，下列敘述何者正確？', '["行政機關得依憲法規定逕命人民履行該義務", "除憲法明定者外，國家不得課予人民其他義務", "就人民義務之具體內容，立法者有形成自由", "人民義務不適用憲法第23條之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00122', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依司法院大法官解釋，有關總統之國家機密特權，下列敘述何者錯誤？', '["總統就國家機密事項於刑事訴訟程序，應享有拒絕證言權", "總統有拒絕提交相關證物之權", "就涉及總統國家機密特權範圍內之國家機密事項之訊問，是否妨害國家之利益，應由總統 證明之", "檢察官若以總統所提交相關證物作為終結偵查之處分，有造成國家安全危險之合理顧慮 者，應認有妨害國家利益之虞"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00123', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '下列何者享有憲法上之主權？', '["花蓮縣", "臺北市", "臺北市政府", "中華民國"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "010d37b27f1c", "answer_pdf_sha1": "03b50faaea82", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
